// Parse the model's text output as JSON. Strip any code fencing if present.
let txt = $input.item.json.completion || $input.item.json.content?.[0]?.text || '';
txt = txt.trim();
if (txt.startsWith('```')) {
  txt = txt.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
}
try {
  const parsed = JSON.parse(txt);
  return { json: parsed };
} catch (e) {
  // Best-effort: try to find a JSON object in the text
  const m = txt.match(/\{[\s\S]*\}/);
  if (m) {
    try { return { json: JSON.parse(m[0]) }; } catch (e2) {}
  }
  throw new Error('Agent returned invalid JSON: ' + txt.slice(0, 500));
}
